const INCIDENT_CATEGORY_OPTIONS = [
  'World Cup 2026',
  'Special Event',
  'Hazardous Materials',
  'Exercise',
] as const

const INCIDENT_CATEGORY_COLORS: Record<(typeof INCIDENT_CATEGORY_OPTIONS)[number], [number, number, number]> = {
  'World Cup 2026': [22, 163, 74],
  'Special Event': [37, 99, 235],
  'Hazardous Materials': [220, 38, 38],
  Exercise: [147, 51, 234],
}

const DEFAULT_INCIDENT_CATEGORY_COLOR: [number, number, number] = [100, 116, 139]

const getIncidentPrimaryCategory = (incident: IncidentListItem) => incident.category

const getIncidentCategoryRgb = (category: string): [number, number, number] =>
  INCIDENT_CATEGORY_COLORS[category as (typeof INCIDENT_CATEGORY_OPTIONS)[number]] ??
  DEFAULT_INCIDENT_CATEGORY_COLOR

const getIncidentCategoryColorHex = (category: string) => {
  const [red, green, blue] = getIncidentCategoryRgb(category)
  return `rgb(${red}, ${green}, ${blue})`
}

const getIncidentCategoryFillColor = (
  category: string,
  alpha = 0.18
): [number, number, number, number] => {
  const [red, green, blue] = getIncidentCategoryRgb(category)
  return [red, green, blue, alpha]
}

const renderIncidentCategoryBadge = (category: string) => (
  <Badge variant="secondary" className="gap-1.5">
    <span
      className="inline-block h-2 w-2 shrink-0 rounded-full"
      style={{ backgroundColor: getIncidentCategoryColorHex(category || 'Uncategorized') }}
      aria-hidden="true"
    />
    {category || 'Uncategorized'}
  </Badge>
)

const matchesIncidentCategoryFilters = (
  incident: IncidentListItem,
  filters: string[]
) => filters.length === 0 || filters.includes(incident.category)

const getIncidentRelatedEventNames = (incident: IncidentListItem, events: EventListItem[]) =>
  incident.relatedEventIds
    .map((eventId) => events.find((event) => event.id === eventId)?.name)
    .filter((name): name is string => Boolean(name))

const getIncidentRelatedEventsLabel = (incident: IncidentListItem, events: EventListItem[]) => {
  const names = getIncidentRelatedEventNames(incident, events)
  if (names.length === 0) {
    return 'No related event'
  }

  if (names.length === 1) {
    return `Related event · ${names[0]}`
  }

  return `Related events · ${names.join('; ')}`
}

const INCIDENT_SEVERITY_ORDER: Record<IncidentListItem['severity'], number> = {
  High: 0,
  Medium: 1,
  Low: 2,
}

const sortIncidentsBySeverity = (incidents: IncidentListItem[]) =>
  [...incidents].sort(
    (a, b) => INCIDENT_SEVERITY_ORDER[a.severity] - INCIDENT_SEVERITY_ORDER[b.severity]
  )

const sortEventsBySeverity = (events: EventListItem[]) =>
  [...events].sort(
    (a, b) => INCIDENT_SEVERITY_ORDER[a.severity] - INCIDENT_SEVERITY_ORDER[b.severity]
  )

const matchesWorkspaceNavSearch = (item: IncidentListItem, query: string) => {
  const normalized = query.trim().toLowerCase()
  if (!normalized) return true

  return [
    item.name,
    item.type,
    item.status,
    item.severity,
    item.region,
    item.lead,
    item.summary,
  ]
    .join(' ')
    .toLowerCase()
    .includes(normalized)
}

const getIncidentSeverityBadgeClasses = (severity: IncidentListItem['severity']) => {
  switch (severity) {
    case 'High':
      return 'border-red-300 bg-red-50 text-red-700 dark:border-red-500/60 dark:bg-red-500/10 dark:text-red-200'
    case 'Medium':
      return 'border-amber-300 bg-amber-50 text-amber-800 dark:border-amber-500/60 dark:bg-amber-500/10 dark:text-amber-200'
    case 'Low':
      return 'border-green-300 bg-green-50 text-green-700 dark:border-green-500/60 dark:bg-green-500/10 dark:text-green-200'
  }
}

type EventCreationKind = 'user' | 'threshold'

type EventListItem = {
  id: number
  name: string
  type: string
  status: 'Active' | 'Monitoring' | 'Demobilizing'
  severity: 'High' | 'Medium' | 'Low'
  region: string
  businessUnit: string
  location: [number, number]
  lead: string
  startedAt: string
  lastUpdate: string
  summary: string
  resourcesCommitted: string
  creationKind: EventCreationKind
  createdByUser: string | null
  thresholdDescription: string | null
  sendNotificationOnCreate: boolean
  notificationRecipients: string
  sourceReport?: InitialIncidentReportState
}

const getEventCreationLabel = (event: EventListItem) => {
  if (event.creationKind === 'user') {
    return `Created by Pratus user · ${event.createdByUser ?? 'Unknown user'}`
  }

  return `Auto-created by Pratus · ${event.thresholdDescription ?? 'Threshold reached'}`
}

const formatInitialIncidentReportSummary = (report: InitialIncidentReportState) => {
  const parts: string[] = []

  if (report.shortDescription.trim()) {
    parts.push(report.shortDescription.trim())
  }

  const locationLabel = [
    ...report.facilityLocations.filter((location) => location !== 'Other'),
    report.facilityLocations.includes('Other') && report.facilityLocationOther.trim()
      ? report.facilityLocationOther.trim()
      : null,
  ]
    .filter((entry): entry is string => Boolean(entry))
    .join(', ')

  if (locationLabel) {
    parts.push(`Location: ${locationLabel}`)
  } else if (report.facilityLocationOther.trim()) {
    parts.push(`Location: ${report.facilityLocationOther.trim()}`)
  }

  if (report.whatHappened.trim()) {
    parts.push(report.whatHappened.trim())
  }

  if (report.icNotified === 'yes' && report.icNotifiedName.trim()) {
    parts.push(`IC notified: ${report.icNotifiedName.trim()}`)
  }

  if (report.scenarios.length > 0) {
    parts.push(`ERP scenarios: ${report.scenarios.join('; ')}`)
  }

  return parts.join(' ')
}

