  useEffect(() => {
    const layer = ics201SketchLayerRef.current
    if (!layer) {
      return
    }
    if (isDrawingIcs201Polygon) {
      return
    }
    layer.removeAll()
    const vertices = ics201EditingMapSketch ? ics201MapSketchDraft : ics201Form.mapSketchPolygon
    if (vertices.length < 3) {
      return
    }
    const ring = vertices.map((vertex) => [vertex.longitude, vertex.latitude])
    const first = ring[0]
    const last = ring[ring.length - 1]
    if (first[0] !== last[0] || first[1] !== last[1]) {
      ring.push([first[0], first[1]])
    }
    layer.add(
      new Graphic({
        geometry: {
          type: 'polygon',
          rings: [ring],
        },
        symbol: {
          type: 'simple-fill',
          color: [37, 99, 235, 0.18],
          outline: {
            color: [37, 99, 235, 1],
            width: 2,
          },
        },
        attributes: {
          mapKey: 'ics201-map-sketch',
          kind: 'ICS-201 Map Sketch',
        },
      })
    )
  }, [ics201Form.mapSketchPolygon, ics201MapSketchDraft, ics201EditingMapSketch, isDrawingIcs201Polygon])

  useEffect(() => {
    ics201EditingMapSketchRef.current = ics201EditingMapSketch
  }, [ics201EditingMapSketch])

  useEffect(() => {
    if (!isDrawingIcs201Polygon) {
      return
    }
    const view = mapViewRef.current
    const layer = ics201SketchLayerRef.current
    if (!view || !layer) {
      setIsDrawingIcs201Polygon(false)
      return
    }
    let cancelled = false
    let svm: SketchViewModel | null = null
    const start = async () => {
      try {
        await view.when()
      } catch {
        return
      }
      if (cancelled) {
        return
      }
      svm = new SketchViewModel({
        view,
        layer,
      })
      ics201SketchViewModelRef.current = svm
      svm.on('create', (event) => {
        if (event.state === 'cancel') {
          setIsDrawingIcs201Polygon(false)
          return
        }
        if (event.state !== 'complete' || !event.graphic?.geometry) {
          return
        }
        const geometry = event.graphic.geometry
        if (geometry.type !== 'polygon') {
          return
        }
        const polygon = geometry as Polygon
        const projected = polygon.spatialReference?.isWebMercator
          ? (webMercatorUtils.webMercatorToGeographic(polygon) as Polygon)
          : polygon
        const sourceRing = projected.rings[0] ?? []
        const trimmed =
          sourceRing.length >= 2 &&
          sourceRing[0][0] === sourceRing[sourceRing.length - 1][0] &&
          sourceRing[0][1] === sourceRing[sourceRing.length - 1][1]
            ? sourceRing.slice(0, -1)
            : sourceRing
        const nextVertices: Ics201MapSketchVertex[] = trimmed.map((point) => ({
          longitude: Number((point[0] ?? 0).toFixed(6)),
          latitude: Number((point[1] ?? 0).toFixed(6)),
        }))
        layer.remove(event.graphic)
        if (ics201EditingMapSketchRef.current) {
          setIcs201MapSketchDraft(nextVertices.map((vertex) => ({ ...vertex })))
        } else {
          updateIcs201Field('mapSketchPolygon', nextVertices)
        }
        setIsDrawingIcs201Polygon(false)
      })
      layer.removeAll()
      svm.create('polygon')
    }
    void start()
    return () => {
      cancelled = true
      if (svm) {
        try {
          svm.cancel()
        } catch {
          /* ignore */
        }
        try {
          svm.destroy()
        } catch {
          /* ignore */
        }
      }
      if (ics201SketchViewModelRef.current === svm) {
        ics201SketchViewModelRef.current = null
      }
    }
  }, [isDrawingIcs201Polygon])

  useEffect(() => {
    const shouldShowModalMap =
      (isCreateIncidentOpen || isCreateExerciseOpen) &&
      (isCreateIncidentOpen ? createIncidentStep : createExerciseStep) === 0
    let isCancelled = false
    let resizeTimeout: ReturnType<typeof setTimeout> | null = null
    let attachRetryHandle = 0

    if (!shouldShowModalMap) {
      setIsCreateIncidentMapReady(false)
      if (createIncidentMapViewRef.current) {
        createIncidentMapViewRef.current.container = null as unknown as HTMLDivElement
      }
      return
    }

    const attachViewToContainer = async () => {
      if (isCancelled) {
        return
      }

      const mapContainer = createIncidentMapContainerRef.current
      if (!mapContainer) {
        attachRetryHandle = window.requestAnimationFrame(() => {
          void attachViewToContainer()
        })
        return
      }

      if (!createIncidentMapViewRef.current) {
        const sourceBasemap = mapViewRef.current?.map?.basemap ?? 'streets-navigation-vector'
        const drawLayer = new GraphicsLayer()
        const clonedMap = new ArcGISMap({
          basemap: sourceBasemap,
          layers: [drawLayer],
        })

        const view = new MapView({
          container: createIncidentMapContainerRef.current,
          map: clonedMap,
          center: mapViewRef.current?.center ?? [-98.5795, 39.8283],
          zoom: mapViewRef.current?.zoom ?? 4,
          ui: {
            components: ['zoom', 'compass'],
          },
        })

        const sketchViewModel = new SketchViewModel({
          view,
          layer: drawLayer,
          updateOnGraphicClick: true,
        })
        sketchViewModel.on('create', (event) => {
          if (event.state !== 'complete' || !event.graphic?.geometry) {
            return
          }

          drawLayer.removeAll()
          drawLayer.add(event.graphic)

          const geometry = event.graphic.geometry
          if (geometry.type === 'point') {
            const point = geometry as Point
            const latitude = point.latitude
            const longitude = point.longitude
            if (latitude == null || longitude == null) {
              setIncidentGeometrySummary('Point selected')
              return
            }

            setIncidentGeometrySummary(
              `Point selected at ${latitude.toFixed(5)}, ${longitude.toFixed(5)}`
            )
            return
          }

          if (geometry.type === 'polygon') {
            const centroid = geometry.extent?.center
            if (centroid) {
              const latitude = centroid.latitude
              const longitude = centroid.longitude
              if (latitude == null || longitude == null) {
                setIncidentGeometrySummary('Polygon selected')
                return
              }

              setIncidentGeometrySummary(
                `Polygon selected near ${latitude.toFixed(5)}, ${longitude.toFixed(5)}`
              )
            } else {
              setIncidentGeometrySummary('Polygon selected')
            }
          }
        })

        createIncidentDrawLayerRef.current = drawLayer
        createIncidentSketchViewModelRef.current = sketchViewModel
        createIncidentMapViewRef.current = view
        positionMapZoomControls(view)
        await view.when()
      } else {
        createIncidentMapViewRef.current.container = mapContainer
        await createIncidentMapViewRef.current.when()
      }

      const modalMapView = createIncidentMapViewRef.current
      if (!modalMapView || isCancelled) {
        return
      }
      setIsCreateIncidentMapReady(true)

      requestAnimationFrame(() => {
        if (isCancelled) {
          return
        }

        window.dispatchEvent(new Event('resize'))
        void modalMapView
          .goTo(
            {
              center: modalMapView.center,
              scale: modalMapView.scale,
            },
            { animate: false }
          )
          .catch(() => {
            // Ignore interrupted goTo calls while the modal is mounting.
          })
      })

      resizeTimeout = setTimeout(() => {
        if (isCancelled) {
          return
        }

        window.dispatchEvent(new Event('resize'))
      }, 150)
    }

    void attachViewToContainer()

    return () => {
      isCancelled = true
      setIsCreateIncidentMapReady(false)
      if (attachRetryHandle) {
        window.cancelAnimationFrame(attachRetryHandle)
      }
      if (resizeTimeout) {
        clearTimeout(resizeTimeout)
      }
      if (createIncidentMapViewRef.current) {
        createIncidentMapViewRef.current.container = null as unknown as HTMLDivElement
      }
    }
  }, [isCreateIncidentOpen, isCreateExerciseOpen, createIncidentStep, createExerciseStep])

