      datetimeOrdered: '04/07/2026 21:00 UTC',
      opcon: 'Planning',
      tacon: 'Planning',
      pointOfContact: 'M. Bennett (555-0113)',
      owningOrganization: 'SEOC',
      quantity: 1,
      unit: 'Cell',
      hullTailNumber: 'N/A',
      symbology: 'Staff',
