                    <ToggleGroupItem
                      value="dark"
                      aria-label="Dark mode"
                      className={glassToggleItemClasses}
                    >
                      <Moon className="h-4 w-4" />
                    </ToggleGroupItem>
                    <ToggleGroupItem
